const svg = $('#ring-svg'), out = $('#ring-out'), dSlider = $('#ring-d');
const dVal = $('#ring-d-val'), prev = $('#ring-d-prev'), next = $('#ring-d-next');

function stepD(dir){
  let d = parseInt(dSlider.value,10);
  while(true){
    d += dir;
    if(d<-10 || d>10){ d = parseInt(dSlider.value,10); break; }
    if(d===0 || d===1) continue;
    if(isSquarefree(d)) break;
  }
  dSlider.value = d;
  render();
}
prev.addEventListener('click', ()=>stepD(-1));
next.addEventListener('click', ()=>stepD(+1));
dSlider.addEventListener('input', render);

function render(){
  let d = parseInt(dSlider.value,10);
  if(d===0) d = -1;
  if(d===1) d = 2;
  const sf = isSquarefree(d);
  dVal.textContent = 'd = ' + d + (sf ? '' : '  (not squarefree — choose another)');
  svg.innerHTML = '';
  if(!sf){
    out.textContent = 'd = '+d+' is not squarefree; K = Q(√d) is not a quadratic field for this d.';
    return;
  }
  const dmod4 = mod(d,4);
  const type = (dmod4===1) ? '1 mod 4' : (dmod4===2 ? '2 mod 4' : '3 mod 4');
  const basis = (dmod4===1) ? '{ 1, (1+√d)/2 }' : '{ 1, √d }';
  const disc = (dmod4===1) ? d : 4*d;
  const K = 'Q(√'+d+')';

  // Draw lattice
  const W=720, H=360, cx=W/2, cy=H/2;
  // choose scale so basis vectors span ~100 px
  let v1, v2; // two basis vectors as complex numbers (real, imag)
  if(d<0){
    const s = Math.sqrt(-d);
    if(dmod4===1){
      v1 = [1,0];
      v2 = [0.5, s/2];
    } else {
      v1 = [1,0];
      v2 = [0, s];
    }
  } else {
    const s = Math.sqrt(d);
    // real quadratic: plot as (σ1(ω), σ2(ω)) = (a+b√d, a-b√d) for basis element ω=a+b√d
    if(dmod4===1){
      v1 = [1,1];
      v2 = [(1+s)/2, (1-s)/2];
    } else {
      v1 = [1,1];
      v2 = [s,-s];
    }
  }
  // determine a reasonable pixel scale
  const maxLen = Math.max(Math.hypot(...v1), Math.hypot(...v2));
  const scale = 80 / Math.max(1, maxLen);

  // draw axes
  svg.appendChild(SVG('line',{x1:30,y1:cy,x2:W-30,y2:cy,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)','stroke-width':1}));
  const axLbl = SVG('text',{x:W-18,y:cy-6,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
  axLbl.textContent = d<0 ? 'Re' : 'σ₁';
  svg.appendChild(axLbl);
  const ayLbl = SVG('text',{x:cx+6,y:28,'font-size':11,fill:'var(--mute)'});
  ayLbl.textContent = d<0 ? 'Im' : 'σ₂';
  svg.appendChild(ayLbl);

  // draw lattice points for a,b in a small range
  const R = 5;
  for(let a=-R;a<=R;a++){
    for(let b=-R;b<=R;b++){
      const x = a*v1[0] + b*v2[0];
      const y = a*v1[1] + b*v2[1];
      const px = cx + x*scale;
      const py = cy - y*scale;
      if(px<10 || px>W-10 || py<10 || py>H-10) continue;
      const isZero = (a===0 && b===0);
      const isBasis = ((a===1 && b===0) || (a===0 && b===1));
      const c = isBasis ? 'var(--yellow)' : (isZero ? 'var(--cyan)' : 'var(--blue)');
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:isBasis?4.5:(isZero?4:2.4),fill:c,opacity:isBasis||isZero?1:0.78}));
    }
  }
  // draw basis vectors from origin
  function drawBasisVec(v, color, label, dx=10, dy=-6){
    const x = v[0]*scale, y = -v[1]*scale;
    svg.appendChild(SVG('line',{x1:cx,y1:cy,x2:cx+x,y2:cy+y,stroke:color,'stroke-width':1.5,opacity:0.9}));
    const t = SVG('text',{x:cx+x+dx,y:cy+y+dy,'font-size':12,fill:color,'font-style':'italic'});
    t.textContent = label;
    svg.appendChild(t);
  }
  drawBasisVec(v1, 'var(--yellow)', 'ω₁');
  drawBasisVec(v2, 'var(--green)',  'ω₂');

  // heading
  const h = SVG('text',{x:W/2,y:18,'text-anchor':'middle','font-size':13,fill:'var(--ink)','font-weight':600});
  h.textContent = 'K = '+K+',  O_K = '+(dmod4===1?'Z[(1+√d)/2]':'Z[√d]');
  svg.appendChild(h);

  const lines = [
    'K = Q(√'+d+'),   d = '+d+'   ('+type+')',
    'ring of integers O_K = '+(dmod4===1?'Z[(1+√'+d+')/2]':'Z[√'+d+']'),
    'integral basis: '+basis,
    'discriminant Δ_K = '+disc,
    d<0
      ? 'imaginary quadratic:  O_K ⊂ C is a rank-2 lattice; fundamental domain area = √|Δ|/2 = '+(Math.sqrt(Math.abs(disc))/2).toFixed(4)
      : 'real quadratic:  embed by (σ₁,σ₂); covolume = √Δ = '+Math.sqrt(disc).toFixed(4)+'.  Fundamental unit gives nontrivial multiplicative symmetry.'
  ];
  out.textContent = lines.join('\n');
}

render();

