/* =============================== SECTION 4: ramification =============================== */
(function(){
  const svg = $('#ram-svg'), out = $('#ram-out');
  const dSel = $('#ram-d'), pSel = $('#ram-p');

  function classify(d, p){
    d = parseInt(d,10); p = parseInt(p,10);
    const dmod4 = mod(d,4);
    // ramification: p | Δ_K
    const disc = (dmod4===1) ? d : 4*d;
    const ramifies = (mod(disc, p) === 0);
    let behavior, e, f, g, factors;
    if(p === 2){
      // handle p=2 by explicit cases based on d mod 8 for d odd; d even always ramifies
      if(mod(d,2)===0){
        behavior='ramifies'; e=2; f=1; g=1;
        factors = ['p₁ = (2, √'+d+')'];
      } else {
        const d8 = mod(d,8);
        if(d8===1){ behavior='splits'; e=1; f=1; g=2;
          factors = ['p₁ = (2, (1+√'+d+')/2)', 'p₂ = (2, (1−√'+d+')/2)']; }
        else if(d8===5){ behavior='inert'; e=1; f=2; g=1;
          factors = ['p = (2)']; }
        else { behavior='ramifies'; e=2; f=1; g=1;
          factors = ['p₁ = (2, 1+√'+d+')']; }
      }
    } else {
      if(ramifies){
        behavior='ramifies'; e=2; f=1; g=1;
        factors = ['p₁ = ('+p+', √'+d+')'];
      } else {
        const sym = legendre(d, p);
        if(sym === 1){
          // split: find r with r^2 ≡ d (mod p)
          let r = 0;
          for(let k=1;k<p;k++){ if(mod(k*k - d, p)===0){ r=k; break; } }
          behavior='splits'; e=1; f=1; g=2;
          factors = ['p₁ = ('+p+', '+r+' − √'+d+')', 'p₂ = ('+p+', '+r+' + √'+d+')'];
        } else {
          behavior='inert'; e=1; f=2; g=1;
          factors = ['p = ('+p+')'];
        }
      }
    }
    return {behavior, e, f, g, factors, sum: e*f*g};
  }

  function render(){
    svg.innerHTML = '';
    const d = dSel.value, p = pSel.value;
    const info = classify(d, p);
    const W=720, H=220;

    // draw the rational prime p on the left, and the primes above it on the right
    const px = 130, py = 110;
    drawNode(svg, px, py, 'p='+p, {r:28, stroke:'var(--violet)', fontSize:14});
    const t1 = SVG('text',{x:px, y:py+58,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t1.textContent = 'in Z';
    svg.appendChild(t1);

    const gx = 520;
    for(let i=0;i<info.g;i++){
      const gy = info.g===1 ? py : (info.g===2 ? (i===0 ? 60 : 160) : 110);
      drawNode(svg, gx, gy, 'p'+(info.g>1?'_'+(i+1):''), {r:28, stroke:'var(--yellow)', fontSize:14});
      const exp = info.e>1 ? ' (e='+info.e+')' : '';
      const rez = info.f>1 ? ' (f='+info.f+')' : '';
      drawArrow(svg, [px, py], [gx, gy], {
        color:'var(--blue)', curve: info.g===2 ? (i===0?-25:25) : 0,
        label: exp+rez, markerId:'ram'+i,
        pad1: 32, pad2: 32
      });
    }
    const t2 = SVG('text',{x:gx, y:py+58,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t2.textContent = 'in O_K';
    svg.appendChild(t2);

    // behavior badge
    const col = info.behavior==='splits' ? 'var(--green)'
               : info.behavior==='inert' ? 'var(--cyan)'
               : 'var(--pink)';
    const bx = SVG('rect',{x:W/2-54,y:12,width:108,height:26,rx:13,fill:'var(--panel2)',stroke:col,'stroke-width':1.4});
    svg.appendChild(bx);
    const bt = SVG('text',{x:W/2,y:29,'text-anchor':'middle','font-size':13,fill:col,'font-weight':600});
    bt.textContent = info.behavior.toUpperCase();
    svg.appendChild(bt);

    const dmod4 = mod(parseInt(d,10),4);
    const dmod8 = mod(parseInt(d,10),8);
    const disc = (dmod4===1) ? parseInt(d,10) : 4*parseInt(d,10);
    const lines = [
      'K = Q(√'+d+'),  p = '+p,
      'discriminant Δ_K = '+disc,
      (parseInt(p,10)===2)
        ? 'p=2 case (d mod 8 = '+dmod8+')'
        : 'Legendre symbol  (d/p) = '+ (mod(disc,parseInt(p,10))===0 ? '0 (p | Δ)' : legendre(parseInt(d,10),parseInt(p,10))),
      'factorization: p O_K = '+info.factors.map((s,i)=>{
        const exp = info.e>1 ? '^'+info.e : '';
        return '('+s+')'+exp;
      }).join(' · '),
      'ramification data:  e = '+info.e+',  f = '+info.f+',  g = '+info.g,
      'check  Σ eᵢ fᵢ = '+info.sum+' = [K:Q] = 2   '+(info.sum===2?'✓':'✗')
    ];
    out.textContent = lines.join('\n');
  }

  dSel.addEventListener('change', render);
  pSel.addEventListener('change', render);
  render();
})();

