const svg = $('#class-svg'), out = $('#class-out');
const btnR = $('#class-showring'), btnI = $('#class-showideal'), btnS = $('#class-showsquare');
let mode = 'ring';

function activate(which){
  [btnR,btnI,btnS].forEach(b=>b.classList.remove('active'));
  ({ring:btnR,ideal:btnI,square:btnS})[which].classList.add('active');
  mode = which;
  render();
}
btnR.addEventListener('click', ()=>activate('ring'));
btnI.addEventListener('click', ()=>activate('ideal'));
btnS.addEventListener('click', ()=>activate('square'));

// O_K = Z + Z√-5; embed via √-5 → i√5
const v1 = [1,0], v2 = [0, Math.sqrt(5)];
const W=720, H=360, cx=W/2, cy=H/2;
const scale = 42;

function inIdeal(a,b){
  // p = (2, 1+√-5)  =>  Z-module gen: {2, 1+√-5, 2√-5 (since p is of index 2)} -> generated as Z-module
  // A rank-2 sublattice with basis (2, 0), (1, 1) in (a,b) coordinates → index 2 in Z^2
  // So (a,b) ∈ p iff a + b ≡ 0 (mod 2).
  return mod(a+b, 2) === 0;
}
function inIdealSq(a,b){
  // p^2 = (2)  =>  (a,b) ∈ (2) iff a,b both even
  return mod(a,2)===0 && mod(b,2)===0;
}

function render(){
  svg.innerHTML = '';
  // axes
