const svg = $('#mink-svg'), out = $('#mink-out');
const a1In=$('#mink-a1'), b1In=$('#mink-b1'), a2In=$('#mink-a2'), b2In=$('#mink-b2');
const rIn=$('#mink-r'), pIn=$('#mink-p'), rv=$('#mink-rv'), pv=$('#mink-pv');
[a1In,b1In,a2In,b2In,rIn,pIn].forEach(el=>el.addEventListener('input', render));
const W=720, H=460, cx=W/2, cy=H/2;

// lgamma approximation for Γ function via Stirling
function lgamma(x){
  // Lanczos g=7 coefficients
  const g=7;
  const c=[0.99999999999980993,676.5203681218851,-1259.1392167224028,771.32342877765313,
           -176.61502916214059,12.507343278686905,-0.13857109526572012,9.9843695780195716e-6,1.5056327351493116e-7];
  if(x<0.5){
    return Math.log(Math.PI/Math.sin(Math.PI*x)) - lgamma(1-x);
  }
  x -= 1;
  let a=c[0];
  const t=x+g+0.5;
  for(let i=1;i<c.length;i++) a += c[i]/(x+i);
  return 0.5*Math.log(2*Math.PI) + (x+0.5)*Math.log(t) - t + Math.log(a);
}
function gamma(x){ return Math.exp(lgamma(x)); }

// 2D volume of ℓ^p ball of radius r: 4 r^2 · Γ(1+1/p)^2 / Γ(1+2/p)
function ballVol(r,p){
  const g1 = gamma(1 + 1/p);
  const g2 = gamma(1 + 2/p);
  return 4 * r*r * g1*g1 / g2;
}

function render(){
  svg.innerHTML = '';
  const a1=parseFloat(a1In.value)||0, b1=parseFloat(b1In.value)||0;
  const a2=parseFloat(a2In.value)||0, b2=parseFloat(b2In.value)||0;
  const r=parseFloat(rIn.value), p=parseFloat(pIn.value);
  rv.textContent = 'r = '+r.toFixed(2);
  pv.textContent = 'p = '+p.toFixed(2);

  const det = Math.abs(a1*b2 - a2*b1);
  const vol = ballVol(r,p);
  const thresh = 4 * det;   // 2^n · covol for n=2
  const meets = vol > thresh;

  // axes
  svg.appendChild(SVG('line',{x1:30,y1:cy,x2:W-30,y2:cy,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)','stroke-width':1}));
  const scale = 60;

  // draw the ℓ^p ball as a polygon
  const N = 200;
  const pts = [];
  for(let k=0;k<N;k++){
    const th = 2*Math.PI*k/N;
    // parametrize: point on unit ℓ^p ball along angle th: (r cosθ, r sinθ) scaled so that ℓ^p norm = 1 (for direction)
    const c = Math.cos(th), s = Math.sin(th);
    const nrm = Math.pow(Math.pow(Math.abs(c),p)+Math.pow(Math.abs(s),p), 1/p);
    const rx = r * c / nrm;
    const ry = r * s / nrm;
    pts.push([cx + rx*scale, cy - ry*scale]);
  }
  const ballPath = SVG('polygon',{
    points: pts.map(q=>q.join(',')).join(' '),
    fill: meets ? 'rgba(131,193,103,0.12)' : 'rgba(224,122,95,0.10)',
    stroke: meets ? 'var(--green)' : 'var(--pink)','stroke-width':1.4
  });
  svg.appendChild(ballPath);

  // lattice points, find the smallest nonzero in the body
  let witness = null; let bestDist = Infinity;
  for(let i=-10;i<=10;i++){
    for(let j=-10;j<=10;j++){
      const x = i*a1 + j*a2;
      const y = i*b1 + j*b2;
      const px = cx + x*scale;
      const py = cy - y*scale;
      if(px<10 || px>W-10 || py<10 || py>H-10) continue;
      // is (x,y) inside the ℓ^p ball of radius r?
      const nrm = Math.pow(Math.pow(Math.abs(x),p)+Math.pow(Math.abs(y),p), 1/p);
      const inBody = (nrm < r);
      const isZero = (i===0 && j===0);
      const c = isZero ? 'var(--cyan)' : (inBody ? 'var(--yellow)' : 'var(--ink)');
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:isZero?5:(inBody?4.5:2.6),fill:c,opacity:isZero||inBody?1:0.7}));
      if(inBody && !isZero){
        const d = Math.hypot(x,y);
        if(d<bestDist){ bestDist=d; witness=[i,j,x,y,px,py]; }
      }
    }
  }
  // highlight witness
  if(witness){
    const [i,j,wx,wy,px,py] = witness;
    svg.appendChild(SVG('circle',{cx:px,cy:py,r:10,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
    const t = SVG('text',{x:px+14,y:py+4,'font-size':12,fill:'var(--yellow)'});
    t.textContent = '('+i+','+j+')';
    svg.appendChild(t);
  }

  // draw basis vectors
  svg.appendChild(SVG('line',{x1:cx,y1:cy,x2:cx+a1*scale,y2:cy-b1*scale,stroke:'var(--blue)','stroke-width':1.8}));
  svg.appendChild(SVG('line',{x1:cx,y1:cy,x2:cx+a2*scale,y2:cy-b2*scale,stroke:'var(--violet)','stroke-width':1.8}));

  const lines = [
    'lattice basis:  v₁ = ('+a1+','+b1+'),  v₂ = ('+a2+','+b2+')',
    'covolume |det(v₁,v₂)| = '+det.toFixed(4),
    'ℓ^'+p.toFixed(2)+' ball of radius '+r.toFixed(2)+'  volume = '+vol.toFixed(4),
    '2ⁿ · covol = 4 · '+det.toFixed(4)+' = '+thresh.toFixed(4),
    meets
      ? '✓ vol > 2ⁿ covol  — Minkowski guarantees a nonzero lattice point in the body'
      : '✗ vol ≤ 2ⁿ covol  — Minkowski gives no guarantee (body may still contain a point)',
    witness
      ? 'found nonzero point '+(witness[0])+'·v₁ + '+(witness[1])+'·v₂ = ('+witness[2].toFixed(3)+', '+witness[3].toFixed(3)+')'
      : 'no nonzero lattice point currently inside'
  ];
  out.textContent = lines.join('\n');
}

render();

