function unitsOf(d){
  // d squarefree, negative
  if(d===-1) return [[1,0],[-1,0],[0,1],[0,-1]].map(([a,b])=>({a,b,text:(a?(a===1?'1':'-1'):'')+(b?((b===1?'+i':'-i')):'')}))
    .map(u=>({...u, label: formatZi(u.a,u.b)}));
  if(d===-3){
    // units: ±1, ±ω, ±ω², where ω=(-1+√-3)/2
    // ω^k for k=0..5 as complex numbers
    const pts = [];
    for(let k=0;k<6;k++){
      const theta = 2*Math.PI*k/6;
      const x = Math.cos(theta), y = Math.sin(theta);
      const lab = k===0?'1':k===1?'ω':k===2?'ω²':k===3?'-1':k===4?'-ω':'-ω²';
      pts.push({x, y, label: lab});
    }
    return pts;
  }
  // only ±1
  return [{x:1,y:0,label:'1'},{x:-1,y:0,label:'-1'}];
}
function formatZi(a,b){
  if(b===0) return ''+a;
  if(a===0) return (b===1?'i':b===-1?'-i':b+'i');
  return a + (b>0?'+':'') + (b===1?'i':b===-1?'-i':b+'i');
}

function render(){
