  svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:'var(--cyan)','stroke-width':1.3,opacity:0.55}));

  let pts;
  if(d===-1){
    pts = [{x:1,y:0,label:'1'},{x:0,y:1,label:'i'},{x:-1,y:0,label:'-1'},{x:0,y:-1,label:'-i'}];
  } else if(d===-3){
    pts = [];
    const labs = ['1','ω','ω²','-1','-ω','-ω²'];
    for(let k=0;k<6;k++){
      const th = 2*Math.PI*k/6;
      pts.push({x:Math.cos(th),y:Math.sin(th),label:labs[k]});
    }
