    const ly = cy - p.y*(R+off);
    const t = SVG('text',{x:lx,y:ly+4,'text-anchor':'middle','font-size':13,fill:'var(--yellow)','font-weight':600});
    t.textContent = p.label;
    svg.appendChild(t);
  });

  // lattice-of-OK sketch: a few lattice points
