  for(let a=-4;a<=4;a++){
    for(let b=-4;b<=4;b++){
      const x = a*v1[0] + b*v2[0];
      const y = a*v1[1] + b*v2[1];
      const px = cx + x*sc;
      const py = cy - y*sc;
      if(px<10 || px>W-10 || py<10 || py>H-10) continue;
      if(Math.hypot(x,y) > 4) continue;
      const isZero = (a===0 && b===0);
      const isUnit = pts.some(p => Math.abs(p.x*R - x*sc) < 1.5 && Math.abs(p.y*R - y*sc) < 1.5);
      if(isUnit) continue;
      const c = isZero ? 'var(--cyan)' : 'var(--mute)';
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:isZero?4:2,fill:c,opacity:isZero?1:0.6}));
    }
  }

