  title.textContent = 'O_K units for d = '+d+' on |z|=1 (yellow); lattice points (grey)';
  svg.appendChild(title);

  let size, descr;
  if(d===-1){ size=4; descr='μ_K = ⟨i⟩ ≅ Z/4'; }
  else if(d===-3){ size=6; descr='μ_K = ⟨ζ₆⟩ ≅ Z/6  (ω = (-1+√-3)/2)'; }
  else { size=2; descr='μ_K = {±1} ≅ Z/2'; }

  const lines = [
    'K = Q(√'+d+'),  signature (0,1),  unit rank = '+(0+1-1)+' = 0',
    '=> O_K^× = μ_K  is finite',
    '|O_K^×| = '+size+'.  '+descr,
    'general imaginary quadratic: extra roots of unity only for d = -1 (i) and d = -3 (ω).'
  ];
  out.textContent = lines.join('\n');
}

