function contFracPell(d){
  // Solve x^2 - d y^2 = ±1 by computing the continued fraction of √d and collecting convergents
  // d positive non-square
  const sqrtD = Math.sqrt(d);
  const a0 = Math.floor(sqrtD);
  if(a0*a0 === d){ return null; }
  // (P, Q) state: root = (sqrt(d) + P)/Q
  let P = 0, Q = 1, a = a0;
  let h1 = 1, h0 = 0, k1 = 0, k0 = 1;
  // first convergent h = a0, k = 1
  let h = a0, k = 1;
  h1 = h; k1 = k; h0 = 1; k0 = 0;
  const seq = [a0];
  for(let step=0; step<80; step++){
    // check  h^2 - d k^2
    const N = h*h - d*k*k;
    if(N === 1 || N === -1){
      return {x:h, y:k, N, period: seq.length-1, seq};
    }
    // next
    P = a*Q - P;
    Q = (d - P*P) / Q;
    a = Math.floor((a0 + P) / Q);
    seq.push(a);
    const hNew = a*h1 + h0;
    const kNew = a*k1 + k0;
    h0 = h1; k0 = k1; h1 = hNew; k1 = kNew;
    h = hNew; k = kNew;
  }
  return null;
}

